import React from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faChartLine, faChartPie, faUserGraduate } from '@fortawesome/free-solid-svg-icons';
import '../';

// Box bileşeni: Daha temiz bir yapı için props kullanıyoruz
const Box = ({ icon, title, items, bgColor }) => (
  <div className="card" style={{ backgroundColor: bgColor }}>
    {/* İkonun içindeki o modern kare kutu */}
    <div className="icon-box">
      <FontAwesomeIcon icon={icon} />
    </div>
    <h2 className="card-title">{title}</h2>
    <ul className="card-list">
      {items.map((item, index) => (
        <li key={index}>{item}</li>
      ))}
    </ul>
  </div>
);

function App() {
  const data = [
    {
      title: "Stock Market Analysis",
      icon: faChartLine, // Grafik yükseliş ikonu
      color: "#3D3A27", // 1. Box rengin
      items: ["Stock Market Analysis", "Stock Market Strategies", "Stock Analysis", "Stock & Analysis"]
    },
    {
      title: "Gryvto Portfolio Strategy",
      icon: faChartPie, // Pasta grafik ikonu
      color: "#113033", // 2. Box rengin
      items: ["Crypto Portfolio Strategy", "Crypto Portfolio", "Crypto Portfolio", "Crypto Recommendations"]
    },
    {
      title: "Rstirement Planning",
      icon: faUserGraduate, // Mezun (emekli hissi) ikonu
      color: "#0E2A2D", // 3. Box rengin
      items: ["Retirement Planning", "Retirement Planning", "Retirement Preparation", "Retirement Planning"]
    }
  ];

  return (
    <div className="container">
      {/* Kutuların ana dizilimi */}
      <div className="box-wrapper">
        {data.map((box, index) => (
          <Box 
            key={index}
            title={box.title}
            icon={box.icon}
            bgColor={box.color}
            items={box.items}
          />
        ))}
      </div>
    </div>
  );
}

export default App;
